module tcp_segmentation(input [15:0] tcp_data, output reg [3:0] seg_type);  
    always @(*) begin  
        if (tcp_data < 512)  
            seg_type = 4'b0001;  
        else if (tcp_data <= 1024)  
            seg_type = 4'b0010;  
        else  
            seg_type = 4'b0011;  
    end  
endmodule
